9	export type ItemType = keyof typeof BASE_PREMIUM;
10	
11	export type Item = { type: ItemType };
12	
13	export function calculateBasePremium(items: Item[]): number {
14	  let sum = 0;
15	  for (const item of items) {
16	    sum += BASE_PREMIUM[item.type];
17	  }
18	  return sum;
19	}
